INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES
('ee9a991d-b770-424c-93bf-ed03493e59c6', 0, 'A relative of a service user replies to your email with: "I''m sorry but this is just not good enough." You need to reply. Which opening is MOST likely to lower the temperature without conceding ground?', 'multiple_choice', '["\"I''m sorry you feel that way, but the position is as set out.\"","\"I understand you''re frustrated. Here is what I can offer.\"","\"Thank you for coming back to me. Let me address each concern directly.\"","\"Your tone is noted, and I''ll respond on the substance below.\""]'::jsonb, '[2]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 1, 'It is 09:00 Monday. Your manager needs a report by 11:00; you''re chairing a 10:00 meeting; a supplier email says they will pause service today over an overdue invoice; a colleague wants to swap a shift next Tuesday. Which do you action FIRST?', 'multiple_choice', '["The report — your manager is waiting.","Spend two minutes ranking all four before doing any.","The shift swap — it''s the smallest item to clear.","The supplier email — to prevent service interruption."]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 2, 'You realise mid-task that you can''t deliver well by the deadline. Which is best?', 'multiple_choice', '["Ask a colleague to take the task on.","Take the time needed and tell the requester after.","Tell the requester now and propose options.","Deliver what you can by the deadline and apologise."]'::jsonb, '[2]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 3, 'When two tasks both feel urgent, the right approach is always to start whichever was given to you first.', 'true_false', '["True","False"]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 4, 'A colleague asks "got a minute?" while you''re in deep focus on a piece of work. Which is best?', 'multiple_choice', '["Ask what it''s about before deciding whether to switch.","Say no firmly so they learn to plan ahead.","Stop immediately — colleagues come first.","Tell them to send it by email."]'::jsonb, '[0]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 5, 'Which of the following should genuinely affect how you prioritise a task?', 'multi_select', '["The deadline.","The seniority of the person who asked.","Whether someone else''s work depends on it.","How interesting you find it.","The consequences if it isn''t done."]'::jsonb, '[0,2,4]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 6, 'You discover a mistake in work that has already gone to a relative. They haven''t raised it. Which is the best NEXT step?', 'multiple_choice', '["Send a corrected version without explanation.","Tell the relative only if they ask.","Wait and see if they raise it.","Tell your manager and agree how to correct it."]'::jsonb, '[3]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 7, 'An email apparently from a senior colleague asks you to send confidential data to an outside address, urgently. The signature looks normal; the reply-to is slightly different from usual. Which is best?', 'multiple_choice', '["Reply asking for written confirmation.","Send the data — the urgency suggests it''s real.","Verify by another channel before doing anything.","Forward to your team to ask if it looks genuine."]'::jsonb, '[2]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 8, 'If a task hasn''t been formally assigned to you, you have no responsibility to flag it.', 'true_false', '["True","False"]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 9, 'You spot a clear error in a document produced by someone several layers above you. Which is best?', 'multiple_choice', '["Raise it privately, framed as a query.","Mention it at the next team meeting.","Say nothing — someone senior will have checked.","Correct it yourself without telling them."]'::jsonb, '[0]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 10, 'You''re asked to do something you''ve never done before. The requester has rushed off. What is the best FIRST step?', 'multiple_choice', '["Look for instructions or a similar example.","Have a go and adjust as you go along.","Wait until they come back to ask them.","Ask the nearest available colleague."]'::jsonb, '[0]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 11, 'Two colleagues each do the same task in slightly different ways, both informally agreed years ago. Which is best?', 'multiple_choice', '["Pick the better method and tell the other to switch.","Raise it with the process owner and document both.","Leave it — both are getting the job done.","Tell both to stop until a process is formalised."]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 12, 'You''re managing six tasks with overlapping deadlines. Which habits help?', 'multi_select', '["Reviewing the list at the start of each day.","Doing the easy ones first to build momentum.","Renegotiating dates as soon as you see a risk.","Saying yes to new work to seem helpful.","Keeping one written list rather than several mental ones."]'::jsonb, '[0,2,4]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 13, 'It''s reasonable to acknowledge an email and indicate when you''ll reply properly, rather than waiting until you have a complete answer.', 'true_false', '["True","False"]'::jsonb, '[0]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 14, 'Two managers give you contradictory instructions for the same task. Which is best?', 'multiple_choice', '["Follow whichever is more senior.","Choose whichever makes more sense to you.","Go back to both and ask them to resolve it.","Follow whichever was most recent."]'::jsonb, '[2]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 15, 'You arrive at work to find a problem you created yesterday is already being fixed by a colleague. Which is best?', 'multiple_choice', '["Take over — it''s your responsibility.","Ask where they''ve got to and how you can help.","Watch quietly so you can learn for next time.","Stay out of it — they''ve already started."]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 16, 'A supplier keeps making minor invoice errors. None is large enough for a formal complaint. Which is best?', 'multiple_choice', '["Switch supplier the next time you can.","Raise the pattern with the supplier directly.","Live with it as part of the role.","Continue correcting each invoice as it arrives."]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 17, 'You''re given a multi-step procedure. Step 4 contradicts step 2. Which is best?', 'multiple_choice', '["Choose whichever is more sensible.","Stop and check with the author.","Follow the earlier step.","Follow the most recent step."]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 18, 'You''re asked to investigate why something went wrong. Which approaches help?', 'multi_select', '["Establish the facts before forming a view.","Speak to those involved separately before drawing conclusions.","Start with a hypothesis and look for supporting evidence.","Note observations that don''t fit your initial impression.","Focus on process factors, not just individuals."]'::jsonb, '[0,1,3,4]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 19, 'When you''ve finished your assigned tasks, the appropriate next step is to wait until more work is allocated.', 'true_false', '["True","False"]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 20, 'A system has a flaw that everyone works around. Which is best?', 'multiple_choice', '["Try to fix the underlying issue yourself.","Continue with the existing workaround.","Wait until someone more senior raises it.","Document the issue and raise it with the system owner."]'::jsonb, '[3]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 21, 'A relative has called five times in three days, each about a slightly different issue. Which is best on the next call?', 'multiple_choice', '["Politely tell them they are calling too often.","Limit the next call to five minutes.","Suggest one longer conversation covering all issues.","Refer them to a different colleague."]'::jsonb, '[2]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 22, 'Your computer freezes and you lose 30 minutes of work, with a deadline approaching. Which is the best FIRST action?', 'multiple_choice', '["Pause, judge whether the deadline still holds, then act.","Restart and redo the lost work immediately.","Switch to a different task and come back later.","Report it to IT and wait for them."]'::jsonb, '[0]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 23, 'When stuck on a problem, the most productive response is to keep working alone for as long as possible before asking for help.', 'true_false', '["True","False"]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 24, 'A task turns out to be more complex than expected. Which responses are sensible early on?', 'multi_select', '["Break it into smaller steps.","Re-read the original request.","Quietly extend the deadline yourself.","Estimate the new effort and flag risk early.","Push through and worry about timing later."]'::jsonb, '[0,1,3]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 25, 'You spot something that looks wrong, in someone else''s area. Which is best?', 'multiple_choice', '["Investigate it yourself.","Raise it neutrally with the area''s owner.","Ignore it — not your responsibility.","Mention it casually at lunch."]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 26, 'You''re summarising a complex situation for a manager known to skim-read. Which structure serves them best?', 'multiple_choice', '["Headline conclusion first, supporting detail beneath.","A single short paragraph and no detail.","Background, then analysis, then conclusion.","Bullet points only, no narrative."]'::jsonb, '[0]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 27, 'A colleague says they''ve finished a shared piece of work. You spot-check it and find a serious error. Which is best?', 'multiple_choice', '["Raise it with their manager.","Raise it privately with them and agree how to correct it.","Fix it yourself without comment.","Send it on with the error noted in a separate email."]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 28, 'If you''re unsure whether a task is yours, the safe default is to assume it isn''t.', 'true_false', '["True","False"]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 29, 'You spend a week on a task and your manager says "this isn''t what I asked for." Which is best?', 'multiple_choice', '["Apologise and agree to start again.","Suggest a colleague takes over the rework.","Defend your interpretation — the brief was unclear.","Clarify what they actually wanted and what is salvageable."]'::jsonb, '[3]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 30, 'You''re chairing a short meeting. Which actions help it run well?', 'multi_select', '["An agenda that participants have seen in advance.","Letting conversation flow rather than tracking time.","Agreeing actions with named owners before closing.","Letting the most senior person dominate to move things along.","A short note afterwards confirming what was agreed."]'::jsonb, '[0,2,4]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 31, 'You need a decision from a colleague before a deadline. You''ve emailed and called — no response for two hours. Which is best?', 'multiple_choice', '["Make the decision unilaterally without their input.","Try another channel; if still no reply, decide and inform them.","Let the deadline pass and pick it up afterwards.","Wait a further two hours and try the same channels."]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 32, 'Your previous meeting overran and you''re now late for one you''re chairing. Which is best?', 'multiple_choice', '["Rush in and apologise as you start.","Message ahead and suggest they begin without you.","Skip the next meeting altogether.","Take a moment to compose yourself before going in."]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 33, 'Before sending an important email, asking "what do I want the reader to do or know?" is a useful habit.', 'true_false', '["True","False"]'::jsonb, '[0]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 34, 'A senior colleague hands you a problem with their preferred solution already decided. You can see a better option. Which is best?', 'multiple_choice', '["Implement both options and let them choose between.","Implement your solution; it''s the better option.","Implement their solution exactly as instructed.","Raise your alternative as a question, then proceed."]'::jsonb, '[3]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 35, 'A system change is going live tomorrow that will affect a process you handle, and you haven''t been briefed. Which is best?', 'multiple_choice', '["Contact the change owner now to clarify impact.","Email your manager to complain about the gap.","Assume you''d have been told if it mattered.","Wait until tomorrow to see what happens."]'::jsonb, '[0]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 36, 'You''ve a small, tedious task on your list. Which is best?', 'multiple_choice', '["Delay it until you have more energy.","Pass it to someone less senior.","Do it badly to clear it from the list.","Tackle it promptly at your normal standard."]'::jsonb, '[3]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 37, 'Which of these are signs that a task may be more urgent than it first appears?', 'multi_select', '["Another person''s work depends on it being done.","Delay increases the cost or difficulty of fixing it.","A relative or service user is being inconvenienced.","The requester has gone quiet since asking.","You find it more interesting than your current work."]'::jsonb, '[0,1,2]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 38, 'You''re given a task similar to one you did a year ago. Which is best?', 'multiple_choice', '["Copy the previous version verbatim and submit.","Use the previous version as a starting point, then adapt.","Start from scratch without referring back.","Decline since you have already done this work."]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 39, 'A process that has always been done a certain way should not be changed.', 'true_false', '["True","False"]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 40, 'The office printer jams frequently. Everyone complains, no one acts. Which is best?', 'multiple_choice', '["Stop using the printer where possible.","Add your voice to the complaints in the kitchen.","Identify the owner and raise the issue with evidence.","Bring in your own printer."]'::jsonb, '[2]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 41, 'If the rota is correct, the team lead is informed. The team lead has not been informed. Which conclusion follows?', 'multiple_choice', '["Nothing can be concluded.","The rota is correct.","Both A and C.","The rota is not correct."]'::jsonb, '[3]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 42, 'All admins in the team have access to the shared inbox. Some admins also have access to the finance system. No one with finance system access works night shifts. Which MUST be true?', 'multiple_choice', '["Anyone who works night shifts is an admin.","Some night-shift workers have finance system access.","No admin in the team who works night shifts has finance system access.","All team admins work night shifts."]'::jsonb, '[2]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 43, 'What number comes next in the sequence: 2, 6, 12, 20, 30, ?', 'multiple_choice', '["36","40","42","44"]'::jsonb, '[2]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 44, 'Premises: All members of Team A speak Spanish. Pam speaks Spanish. Which conclusion follows?', 'multiple_choice', '["Some Team A members do not speak Spanish.","Pam is not in Team A.","Whether Pam is in Team A cannot be determined.","Pam is in Team A."]'::jsonb, '[2]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 45, 'If overtime is approved, the rota is updated. If the rota is updated, the team lead is notified. The team lead has NOT been notified. Which must be true?', 'multiple_choice', '["The rota has not been updated.","Neither A nor B.","Both A and B.","Overtime was not approved."]'::jsonb, '[2]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 46, 'A bus leaves the depot at 08:00 at 30 mph. A second bus leaves the same depot at 09:00 along the same route at 45 mph. When does the second bus catch the first?', 'multiple_choice', '["10:00","10:30","11:00","11:30"]'::jsonb, '[2]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 47, 'From the premise "All careful workers complete their checks" it logically follows that "All those who complete their checks are careful workers."', 'true_false', '["True","False"]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 48, 'Five colleagues sit in a row. Eva is at the left end. Dan is at the right end. Ben does not sit next to Eva. Asha sits next to Carla. Which must be true?', 'multiple_choice', '["Asha is in position 3.","Carla is in position 3.","Asha is in position 2.","Ben is in position 4."]'::jsonb, '[3]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 49, 'Argument: "No staff have complained about the new system this week, so it must be working well." Which assumption is the argument relying on?', 'multiple_choice', '["The system replaced a flawed predecessor.","Staff would complain if there were problems.","The system has been used this week.","Most staff use the new system regularly."]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 50, 'Which argument contains the SAME flaw as: "Sales rose after we changed the logo, so the logo change caused the rise"?', 'multiple_choice', '["All my emails were sent, so my outbox is empty.","Most accidents happen on weekends, so weekends are inherently dangerous.","Everyone in the team uses Excel, so Excel must be the most popular software.","It rained after we washed the car, so washing the car caused the rain."]'::jsonb, '[3]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 51, 'Three colleagues — X, Y, Z — each prefer one drink: coffee, tea, or water. X does not drink coffee. Z does not drink tea. Y drinks neither water nor coffee. Who drinks what?', 'multiple_choice', '["X-water, Y-tea, Z-coffee","X-coffee, Y-tea, Z-water","X-tea, Y-water, Z-coffee","X-water, Y-coffee, Z-tea"]'::jsonb, '[0]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 52, 'What comes next in the sequence: J, F, M, A, M, J, ?', 'multiple_choice', '["A","J","S","F"]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 53, 'A fair coin has landed heads on each of the last eight tosses. On the ninth toss:', 'multiple_choice', '["Tails is more likely because heads is overdue.","Heads is more likely because the streak is continuing.","It is impossible to say anything about the next toss.","Heads and tails are equally likely."]'::jsonb, '[3]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 54, 'Six staff are arranged from shortest to tallest. Priya is taller than Quinn but shorter than Rashid. Sam is shorter than Quinn. Tom is taller than Rashid. Uma is shorter than Sam. What is the order from shortest to tallest?', 'multiple_choice', '["Uma, Sam, Quinn, Rashid, Priya, Tom","Sam, Quinn, Uma, Priya, Rashid, Tom","Sam, Uma, Quinn, Priya, Rashid, Tom","Uma, Sam, Quinn, Priya, Rashid, Tom"]'::jsonb, '[3]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 55, 'Claim: "If a meeting overruns, refreshments are usually offered." Which finding, if true, would MOST weaken the claim?', 'multiple_choice', '["Many meetings overrun but no refreshments are offered.","Some meetings never overrun.","Refreshments are always offered at the start.","Refreshments are sometimes offered at short meetings."]'::jsonb, '[0]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 56, 'What comes next: 1, 4, 9, 16, 25, ?', 'multiple_choice', '["30","34","36","42"]'::jsonb, '[2]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 57, 'Premises: "All engineers wear safety boots." "Some engineers also wear hi-vis vests." Which conclusions follow?', 'multi_select', '["Some who wear safety boots also wear hi-vis vests.","Everyone wearing a hi-vis vest is an engineer.","Some hi-vis vest wearers wear safety boots.","All engineers wear hi-vis vests.","No one wearing a hi-vis vest is an engineer."]'::jsonb, '[0,2]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 58, 'If "All dogs are mammals" is true, then "All mammals are dogs" must also be true.', 'true_false', '["True","False"]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 59, 'Three colleagues each make one statement. Alex: "Ben is lying." Ben: "Carla is lying." Carla: "Both Alex and Ben are lying." Exactly one is telling the truth. Who?', 'multiple_choice', '["Ben","Cannot be determined.","Alex","Carla"]'::jsonb, '[0]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 60, 'All employees are required to wear ID badges in the building. Tomás is in the building wearing an ID badge. Which conclusion follows?', 'multiple_choice', '["Everyone wearing an ID badge is an employee.","None of these necessarily follows.","Tomás is an employee.","Tomás cannot be a visitor."]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 61, 'You''re at a social event. Someone asks what you do, then begins probing about your workplace and a service user they think they know. Which is best?', 'multiple_choice', '["Confirm the connection and chat openly about it.","Pretend you don''t actually work there.","Keep your answer general — focus on what you do.","Discuss only what is in the public domain."]'::jsonb, '[2]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 62, 'It is fine to discuss work in detail with your partner at home, as long as you don''t name anyone specifically.', 'true_false', '["True","False"]'::jsonb, '[1]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 63, 'A client offers you a £20 gift voucher to thank you for help you gave. Which is best?', 'multiple_choice', '["Decline and suggest other ways to thank the team.","Decline on the grounds it is against policy.","Accept — refusing would seem ungracious.","Accept and share it with colleagues."]'::jsonb, '[0]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 64, 'Which of these are inappropriate uses of social media in a work context?', 'multi_select', '["Posting \"another nightmare day at work\" without naming anyone.","Posting a photo from inside the workplace with a service user in the background.","Sharing your employer''s official public post from the company page.","Accepting a friend request from a service user''s relative.","Commenting on a post that criticises a colleague by name."]'::jsonb, '[0,1,3,4]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 65, 'You''re going to be 30 minutes late for the second time in a fortnight. Which is best?', 'multiple_choice', '["Tell your manager briefly and make up the time.","Take the time as annual leave each time.","Say nothing and quietly make up the time.","Mention it to colleagues but not the manager."]'::jsonb, '[0]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 66, 'A service user''s relative wants to connect with you on a personal social-media account. Which is best?', 'multiple_choice', '["Decline and direct them to the official channel.","Block them outright with no explanation.","Accept the request — refusing seems rude.","Accept but restrict what they can see."]'::jsonb, '[0]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 67, 'You realise you''ve made an error in a piece of work that has been signed off and sent. No one has noticed. Which is best?', 'multiple_choice', '["Wait to see if it''s raised.","Make a quiet correction in the next version.","Tell only those you think are directly affected.","Inform your manager and propose how to correct it."]'::jsonb, '[3]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 68, 'Which of these are professional behaviours in a workplace?', 'multi_select', '["Being on time and prepared.","Owning mistakes openly rather than hiding them.","Speaking about colleagues the same in their absence as in their presence.","Keeping a colleague''s confidence by withholding from your manager.","Doing what you said you would do, by when you said you''d do it."]'::jsonb, '[0,1,2,4]'::jsonb, 1),
('ee9a991d-b770-424c-93bf-ed03493e59c6', 69, 'A colleague asks you to clock in for them while they slip out for half an hour. They will make the time up later. Which is best?', 'multiple_choice', '["Clock them in but also message the manager privately.","Agree just this once — they have promised to make it up.","Tell their manager straight away that they''ve gone out.","Refuse — signing in falsely is dishonest, intent aside."]'::jsonb, '[3]'::jsonb, 1);
